import json

BC=r'[.pnbrqkPNBRQK]'

def idx(r,f): return r*8+f
def name(i):
    r,f=i//8,i%8
    return chr(ord('a')+f)+str(8-r)

def squares_along(r,f,dr,df):
    res=[]; nr,nf=r+dr,f+df
    while 0<=nr<8 and 0<=nf<8:
        res.append((nr,nf)); nr+=dr; nf+=df
    return res

class Pat:
    def __init__(self): self.toks=[]; self.n=0
    def lit(self,s): self.toks.append(s)
    def cap(self,rx): self.n+=1; self.toks.append('('+rx+')'); return self.n
    def build(self): return ''.join(self.toks)

def scan_board(P,specials,want_new):
    # specials: idx -> (mpat,cap,src_char,new_char)
    src=[]; new=[]; i=0
    for k in sorted(specials):
        if k>i:
            g=P.cap(BC+'{'+str(k-i)+'}')
            src.append('\\g<%d>'%g)
            if want_new: new.append('\\g<%d>'%g)
        mpat,cap,sc,nc=specials[k]
        if cap:
            g=P.cap(mpat); src.append('\\g<%d>'%g)
        else:
            P.lit(mpat); src.append(sc)
        if want_new: new.append(nc)
        i=k+1
    if i<64:
        g=P.cap(BC+'{'+str(64-i)+'}')
        src.append('\\g<%d>'%g)
        if want_new: new.append('\\g<%d>'%g)
    return ''.join(src),''.join(new)

def castle_effect(fi,ti,is_king):
    c=set()
    if is_king: c|={0,1}
    if fi==63: c.add(0)
    if fi==56: c.add(1)
    if ti==0: c.add(3)
    if ti==7: c.add(2)
    return c

def move_rule(specials,slots_clear,new_ep,slot_pats=None,ep_pat=r'\S+',flags_pat=r'[A-]{5}'):
    P=Pat(); P.lit('\n')
    src,new=scan_board(P,specials,True)
    P.lit(' w ')
    if slot_pats is None: slot_pats=['[K-]','[Q-]','[k-]','[q-]']
    sg=[P.cap(sp) for sp in slot_pats]
    P.lit(' '); eg=P.cap(ep_pat); P.lit(' '); fg=P.cap(flags_pat); P.lit('\n')
    pattern=P.build()
    srcslots=''.join('\\g<%d>'%g for g in sg)
    srcline='\n'+src+' w '+srcslots+' \\g<%d> \\g<%d>\n'%(eg,fg)
    newslots=''.join('-' if j in slots_clear else '\\g<%d>'%sg[j] for j in range(4))
    newline=new+' b '+newslots+' '+new_ep+'\n'
    return [pattern,srcline+newline]

def flag_rule(flagpos,specials):
    P=Pat(); P.lit('\n')
    src,_=scan_board(P,specials,False)
    P.lit(' w ')
    sg=[P.cap(sp) for sp in ['[K-]','[Q-]','[k-]','[q-]']]
    P.lit(' '); eg=P.cap(r'\S+'); P.lit(' ')
    fgs=[P.cap('.') for _ in range(5)]
    P.lit('\n')
    pattern=P.build()
    fout=''.join('A' if j==flagpos else '\\g<%d>'%fgs[j] for j in range(5))
    repl='\n'+src+' w '+''.join('\\g<%d>'%g for g in sg)+' \\g<%d> '%eg+fout+'\n'
    return [pattern,repl]

def kdelete_rule(nocap):
    P=Pat(); P.lit('\n'); i=0
    for k in sorted(nocap):
        if k>i: P.lit(BC+'{'+str(k-i)+'}')
        P.lit(nocap[k]); i=k+1
    if i<64: P.lit(BC+'{'+str(64-i)+'}')
    P.lit(' b [^\\n]*')
    return [P.build(),'']

def black_attack_geoms(s):
    r,f=s//8,s%8; g=[]
    for df in (-1,1):
        nr,nf=r-1,f+df
        if 0<=nr<8 and 0<=nf<8: g.append((idx(nr,nf),'p',[]))
    for dr,df in [(-1,-2),(-1,2),(1,-2),(1,2),(-2,-1),(-2,1),(2,-1),(2,1)]:
        nr,nf=r+dr,f+df
        if 0<=nr<8 and 0<=nf<8: g.append((idx(nr,nf),'n',[]))
    for dr in (-1,0,1):
        for df in (-1,0,1):
            if dr==0 and df==0: continue
            nr,nf=r+dr,f+df
            if 0<=nr<8 and 0<=nf<8: g.append((idx(nr,nf),'k',[]))
    for dr,df in [(-1,0),(1,0),(0,-1),(0,1)]:
        line=squares_along(r,f,dr,df)
        for k in range(len(line)):
            inter=[idx(a,b) for a,b in line[:k]]
            g.append((idx(*line[k]),'[rq]',inter))
    for dr,df in [(-1,-1),(-1,1),(1,-1),(1,1)]:
        line=squares_along(r,f,dr,df)
        for k in range(len(line)):
            inter=[idx(a,b) for a,b in line[:k]]
            g.append((idx(*line[k]),'[bq]',inter))
    return g

rules=[]
# ---- phase 0 preprocessing ----
rules.append([r' \d+ \d+$',''])
for d in range(1,9):
    rules.append([str(d)+r'(?=[^ ]* w)','.'*d])
rules.append([r'/',''])
# castle to 4-slot
for m in range(16):
    letters=''
    for b,ch in enumerate('KQkq'):
        if m&(1<<b): letters+=ch
    tok=letters if letters else '-'
    slot4=''.join(ch if (m&(1<<b)) else '-' for b,ch in enumerate('KQkq'))
    rules.append([' w '+tok+' ',' w '+slot4+' '])
rules.append([r'^(.*)$','\n\\g<1> -----\n'])

# ---- phase 1 flag detection ----
flagsquares=[58,59,60,61,62]  # c1,d1,e1,f1,g1
for fp,s in enumerate(flagsquares):
    for att,cls,inter in black_attack_geoms(s):
        sp={att:(cls,True,None,None)}
        for it in inter: sp[it]=(r'\.',False,'.','.')
        rules.append(flag_rule(fp,sp))

# ---- phase 2 move generation ----
KN=[(-1,-2),(-1,2),(1,-2),(1,2),(-2,-1),(-2,1),(2,-1),(2,1)]
KG=[(dr,df) for dr in(-1,0,1) for df in(-1,0,1) if not(dr==0 and df==0)]
ROOK=[(-1,0),(1,0),(0,-1),(0,1)]
BISH=[(-1,-1),(-1,1),(1,-1),(1,1)]
tgt=r'[.pnbrq]'
for r in range(8):
    for f in range(8):
        fi=idx(r,f)
        # knight
        for dr,df in KN:
            nr,nf=r+dr,f+df
            if 0<=nr<8 and 0<=nf<8:
                ti=idx(nr,nf)
                sp={fi:('N',False,'N','.'),ti:(tgt,True,None,'N')}
                rules.append(move_rule(sp,castle_effect(fi,ti,False),'-'))
        # king (non-castling)
        for dr,df in KG:
            nr,nf=r+dr,f+df
            if 0<=nr<8 and 0<=nf<8:
                ti=idx(nr,nf)
                sp={fi:('K',False,'K','.'),ti:(tgt,True,None,'K')}
                rules.append(move_rule(sp,castle_effect(fi,ti,True),'-'))
        # sliding
        for piece,dirs in [('R',ROOK),('B',BISH),('Q',ROOK+BISH)]:
            for dr,df in dirs:
                line=squares_along(r,f,dr,df)
                for k in range(len(line)):
                    ti=idx(*line[k])
                    sp={fi:(piece,False,piece,'.')}
                    for a,b in line[:k]: sp[idx(a,b)]=(r'\.',False,'.','.')
                    sp[ti]=(tgt,True,None,piece)
                    rules.append(move_rule(sp,castle_effect(fi,ti,False),'-'))
# pawns
for r in range(1,7):
    for f in range(8):
        fi=idx(r,f)
        # forward1
        ti=idx(r-1,f); npc='Q' if r-1==0 else 'P'
        sp={fi:('P',False,'P','.'),ti:(r'\.',False,'.',npc)}
        rules.append(move_rule(sp,castle_effect(fi,ti,False),'-'))
        # forward2
        if r==6:
            m1=idx(5,f); m2=idx(4,f)
            sp={fi:('P',False,'P','.'),m1:(r'\.',False,'.','.'),m2:(r'\.',False,'.','P')}
            rules.append(move_rule(sp,set(),name(m1)))
        # captures
        for df in (-1,1):
            nf=f+df
            if 0<=nf<8:
                ti=idx(r-1,nf); npc='Q' if r-1==0 else 'P'
                sp={fi:('P',False,'P','.'),ti:(r'[pnbrq]',True,None,npc)}
                rules.append(move_rule(sp,castle_effect(fi,ti,False),'-'))
# en passant
for f in range(8):
    et=idx(2,f); cap=idx(3,f)
    for fw in (f-1,f+1):
        if 0<=fw<8:
            frm=idx(3,fw)
            sp={frm:('P',False,'P','.'),cap:('p',False,'p','.'),et:(r'\.',False,'.','P')}
            rules.append(move_rule(sp,set(),'-',ep_pat=name(et)))
# castling
# kingside: e1=60 f1=61 g1=62 h1=63 ; need slot0=K, flags e1,f1,g1(-)
sp={60:('K',False,'K','.'),61:(r'\.',False,'.','R'),62:(r'\.',False,'.','K'),63:('R',False,'R','.')}
rules.append(move_rule(sp,{0,1},'-',slot_pats=['K','[Q-]','[k-]','[q-]'],flags_pat=r'[A-][A-]---'))
# queenside: a1=56 b1=57 c1=58 d1=59 e1=60 ; need slot1=Q, flags c1,d1,e1(-), b1 empty
sp={56:('R',False,'R','.'),57:(r'\.',False,'.','.'),58:(r'\.',False,'.','K'),59:(r'\.',False,'.','R'),60:('K',False,'K','.')}
rules.append(move_rule(sp,{0,1},'-',slot_pats=['[K-]','Q','[k-]','[q-]'],flags_pat=r'---[A-][A-]'))

# ---- phase 3 delete source ----
rules.append([r'\n[^\n]* w [^\n]*',''])

# ---- phase 4 delete illegal (white K attacked) ----
for k in range(64):
    for att,cls,inter in black_attack_geoms(k):
        nc={k:'K',att:cls}
        for it in inter: nc[it]=r'\.'
        rules.append(kdelete_rule(nc))

# ---- phase 5 finalize ----
# slashes
rules.append([r'\n'+(BC+'{8}')*8+' b','\n'+'/'.join('\\g<%d>'%i for i in range(1,9))+' b'])
# hmm build slash pattern with groups explicitly below
rules.pop()
P=Pat(); P.lit('\n'); gs=[P.cap(BC+'{8}') for _ in range(8)]; P.lit(' b')
rules.append([P.build(),'\n'+'/'.join('\\g<%d>'%g for g in gs)+' b'])
# digits
for n in range(8,0,-1):
    rules.append([r'\.{'+str(n)+'}',str(n)])
# castle compact
for m in range(16):
    slot4=''.join(ch if (m&(1<<b)) else '-' for b,ch in enumerate('KQkq'))
    letters=''.join(ch for b,ch in enumerate('KQkq') if m&(1<<b))
    comp=letters if letters else '-'
    rules.append([' b '+slot4+' ',' b '+comp+' '])
# append 0 0
rules.append([r'( b [^\n]+)\n','\\g<1> 0 0\n'])
# strip sentinels
rules.append([r'\A\n',''])
rules.append([r'\n\Z',''])

print('num rules',len(rules))
json.dump(rules,open('/app/re.json','w'))
import os
print('bytes',os.path.getsize('/app/re.json'))

